+/**
+ * Service for managing user notification preferences.
+ *
+ * Provides CRUD operations and preference lookups.
+ * Creates default preferences (all enabled, immediate frequency)
+ * when none exist for a user.
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type {
+  UserNotificationPreferences,
+  UpdateEmailPreferencesInput,
+} from '../models/user-preferences.js';
+import { defaultEmailPreferences } from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset the ID counter. Useful for testing. */
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private preferencesRepository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user, creating defaults if none exist.
+   */
+  getOrCreatePreferences(userId: string): UserNotificationPreferences {
+    const existing = this.preferencesRepository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+
+    this.logger.info(`Creating default preferences for user ${userId}`);
+    const now = new Date();
+    const prefs: UserNotificationPreferences = {
+      id: generatePreferencesId(),
+      userId,
+      email: defaultEmailPreferences(),
+      createdAt: now,
+      updatedAt: now,
+    };
+    return this.preferencesRepository.save(prefs);
+  }
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getPreferences(userId: string): UserNotificationPreferences | undefined {
+    return this.preferencesRepository.findByUserId(userId);
+  }
+
+  /**
+   * Update email preferences for a user. Creates defaults first if none exist.
+   */
+  updateEmailPreferences(
+    userId: string,
+    input: UpdateEmailPreferencesInput,
+  ): UserNotificationPreferences {
+    const prefs = this.getOrCreatePreferences(userId);
+
+    const updatedEmail = { ...prefs.email };
+
+    if (input.enabled !== undefined) {
+      updatedEmail.enabled = input.enabled;
+    }
+    if (input.frequency !== undefined) {
+      updatedEmail.frequency = input.frequency;
+    }
+    if (input.categorySubscriptions) {
+      updatedEmail.categorySubscriptions = {
+        ...updatedEmail.categorySubscriptions,
+        ...input.categorySubscriptions,
+      };
+    }
+
+    this.logger.info(`Updating email preferences for user ${userId}`);
+    return this.preferencesRepository.update(prefs.id, {
+      email: updatedEmail,
+      updatedAt: new Date(),
+    });
+  }
+
+  /**
+   * Check if a user should receive a notification of the given type via email.
+   * Returns true if: email is enabled AND the specific category is subscribed.
+   * If no preferences exist, defaults to true (opt-out model).
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.preferencesRepository.findByUserId(userId);
+    if (!prefs) {
+      return true;
+    }
+    if (!prefs.email.enabled) {
+      return false;
+    }
+    return prefs.email.categorySubscriptions[notificationType] !== false;
+  }
+
+  /**
+   * Delete preferences for a user.
+   */
+  deletePreferences(userId: string): boolean {
+    const prefs = this.preferencesRepository.findByUserId(userId);
+    if (!prefs) {
+      return false;
+    }
+    return this.preferencesRepository.delete(prefs.id);
+  }
+}

