import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categorySubscriptions['order:confirmation']).toBe(true);
      expect(prefs.email.categorySubscriptions['order:status-update']).toBe(true);
      expect(prefs.email.categorySubscriptions['user:welcome']).toBe(true);
      expect(prefs.email.categorySubscriptions['user:profile-updated']).toBe(true);
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repo.count()).toBe(1);
    });

    it('should create separate preferences per user', () => {
      service.getOrCreatePreferences('user-1');
      service.getOrCreatePreferences('user-2');

      expect(repo.count()).toBe(2);
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for a user without preferences', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return preferences after they are created', () => {
      service.getOrCreatePreferences('user-1');
      const prefs = service.getPreferences('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate');
    });

    it('should update frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update individual category subscriptions', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        categorySubscriptions: { 'order:status-update': false },
      });

      expect(updated.email.categorySubscriptions['order:status-update']).toBe(false);
      expect(updated.email.categorySubscriptions['order:confirmation']).toBe(true);
    });

    it('should create defaults first if no preferences exist', () => {
      const updated = service.updateEmailPreferences('user-1', { enabled: false });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.enabled).toBe(false);
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', { frequency: 'weekly-digest' });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(created.updatedAt.getTime());
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return true with default preferences', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false when specific category is unsubscribed', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', {
        categorySubscriptions: { 'order:status-update': false },
      });

      expect(service.shouldSendEmail('user-1', 'order:status-update')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when email disabled even if category is subscribed', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false when no preferences exist', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    const repo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repo);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  it('should send notification when no preferences exist (opt-out model)', async () => {
    await eventBus.emit(orderCreatedEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.getOrCreatePreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', { enabled: false });

    await eventBus.emit(orderCreatedEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(0);
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.getOrCreatePreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      categorySubscriptions: { 'order:confirmation': false },
    });

    await eventBus.emit(orderCreatedEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(0);
  });

  it('should send notification when category is subscribed', async () => {
    preferencesService.getOrCreatePreferences('alice@example.com');

    await eventBus.emit(orderCreatedEvent);

    const notifications = notificationService.getNotifications();
    expect(notifications).toHaveLength(1);
  });

  it('should work without preferences service set (backwards compatible)', async () => {
    const standaloneService = new NotificationService(eventBus);
    // No preferences service set
    const standaloneBus = new EventBus();
    const standaloneNotif = new NotificationService(standaloneBus);

    await standaloneBus.emit(orderCreatedEvent);

    const notifications = standaloneNotif.getNotifications();
    expect(notifications).toHaveLength(1);
  });
});
